1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	};
7	
8	const basePremium = (item: { type: string }): number =>
9	  BASE_PREMIUMS[item.type] ?? 0;
10	
11	export const processSteps = (customer: unknown, steps: Array<{ op: string; items: Array<{ type: string }> }>): unknown => {
12	  return steps.map((step) => {
13	    const itemsTotal = step.items.reduce((sum, item) => sum + basePremium(item), 0);
14	    return { premium: itemsTotal + PROCESSING_FEE };
15	  });
16	};
